const now = new Date();

// n8n should run this on Thursday.
// Report covers previous Thursday 00:00:00 through Wednesday 23:59:59.

const start = new Date(now);
start.setDate(now.getDate() - 7);
start.setHours(0, 0, 0, 0);

const end = new Date(now);
end.setDate(now.getDate() - 1);
end.setHours(23, 59, 59, 999);

const formatDate = (date) => {
  return date.toISOString();
};

return [
  {
    json: {
      report_start: formatDate(start),
      report_end: formatDate(end),
      report_label: `${start.toDateString()} - ${end.toDateString()}`
    }
  }
];

const range = $('Set Report Date Range').first().json;
const start = new Date(range.report_start);
const end = new Date(range.report_end);

const jobOpeningResponse = $('Zoho - Get Job Openings').first().json;
const applicationResponse = $('Zoho - Get Applications').first().json;
const interviewResponse = $('Zoho - Get Interviews').first().json;

const jobs = jobOpeningResponse.data || [];
const applications = applicationResponse.data || [];
const interviews = interviewResponse.data || [];

function normalizeLookup(value) {
  if (!value) return '';
  if (typeof value === 'string') return value;
  if (value.name) return value.name;
  return String(value);
}

function isWithinRange(value) {
  if (!value) return false;
  const date = new Date(value);
  return date >= start && date <= end;
}

function getJobTitleFromJob(job) {
  return normalizeLookup(
    job.Job_Opening_Name ||
    job.Posting_Title ||
    job.Job_Title ||
    job['Job Opening Name']
  );
}

function getJobTitleFromApplication(app) {
  return normalizeLookup(
    app.Job_Opening_Name ||
    app.Posting_Title ||
    app.Job_Opening_ID
  );
}

function getJobTitleFromInterview(interview) {
  return normalizeLookup(interview.Job_Opening_Name);
}

function getClientFromJob(job) {
  return normalizeLookup(
    job.Department_Name ||
    job.Client ||
    job.Client_Name ||
    job.Account_Name ||
    job.Department ||
    job.Hiring_Manager_Details
  );
}

function getStatusFromJob(job) {
  const status = normalizeLookup(
    job.Job_Opening_Status ||
    job.Job_Status ||
    job.Status ||
    job.Publish
  );
  if (status === '838160000000539125') {
    return 'In-progress';
  }
  return status;
}

function parseSalaryRange(salaryStr) {
  if (!salaryStr) return { min: 0, max: 0 };
  let cleanStr = salaryStr
    .replace(/RD\$/g, '')
    .replace(/RD/g, '')
    .replace(/DOP/g, '')
    .replace(/\$/g, '')
    .replace(/,/g, '')
    .trim();
  cleanStr = cleanStr.replace(/ to /gi, '|').replace(/to/gi, '|').replace(/[\t\-–]/g, '|');
  const parts = cleanStr.split('|').map(p => p.trim()).filter(Boolean);
  if (parts.length === 1) {
    const val = parseFloat(parts[0]);
    return isNaN(val) ? { min: 0, max: 0 } : { min: val, max: val };
  } else if (parts.length >= 2) {
    const minVal = parseFloat(parts[0]);
    const maxVal = parseFloat(parts[1]);
    return {
      min: isNaN(minVal) ? 0 : minVal,
      max: isNaN(maxVal) ? 0 : maxVal
    };
  }
  return { min: 0, max: 0 };
}

function parseBillingRate(billingStr) {
  if (!billingStr) return 0;
  let cleanStr = billingStr
    .replace(/USD/gi, '')
    .replace(/\$/g, '')
    .replace(/,/g, '')
    .trim();
  cleanStr = cleanStr.replace(/ to /gi, '|').replace(/to/gi, '|').replace(/[\t\-–]/g, '|');
  const parts = cleanStr.split('|').map(p => p.trim()).filter(Boolean);
  if (parts.length === 1) {
    const val = parseFloat(parts[0]);
    return isNaN(val) ? 0 : val;
  } else if (parts.length >= 2) {
    const val1 = parseFloat(parts[0]);
    const val2 = parseFloat(parts[1]);
    const maxVal = Math.max(isNaN(val1) ? 0 : val1, isNaN(val2) ? 0 : val2);
    return maxVal;
  }
  return 0;
}

function emptyRow(title = '') {
  return {
    'Report Period': range.report_label,
    'Job Title': title,
    'Client': '',
    'Job Opening Status': '',
    'Total Candidates in Job Opening': 0,
    'Candidates Worked This Week': 0,
    'Candidates Invited to Book': 0,
    'Candidates Booked': 0,
    'Candidates Interviewed': 0,
    'Salary Range DOP': '',
    'Salary Min DOP': 0,
    'Salary Max DOP': 0,
    'Billing Rate USD Monthly': '',
    'Estimated Annual Revenue USD': '',
    'Estimated Salary Max USD': '',
    'Estimated Monthly Gross Profit USD': '',
    'Gross Margin %': '',
    'Data Quality Notes': 'OK'
  };
}

const reportByJob = {};

// 1. Create base rows from Job Openings
for (const job of jobs) {
  const title = getJobTitleFromJob(job);
  if (!title) continue;

  if (!reportByJob[title]) {
    reportByJob[title] = emptyRow(title);
  }

  const client = getClientFromJob(job);
  reportByJob[title]['Client'] = client;
  reportByJob[title]['Job Opening Status'] = getStatusFromJob(job);

  reportByJob[title]['Total Candidates in Job Opening'] = job.No_of_Candidates_Associated || 0;

  // Populate financial fields
  const salaryStr = job.Salary || '';
  reportByJob[title]['Salary Range DOP'] = salaryStr;

  const sal = parseSalaryRange(salaryStr);
  reportByJob[title]['Salary Min DOP'] = sal.min;
  reportByJob[title]['Salary Max DOP'] = sal.max;

  const billingRate = job.Billing_to_Client;
  if (billingRate !== null && billingRate !== undefined && billingRate !== '') {
    const brVal = parseBillingRate(billingRate);
    if (brVal > 0) {
      reportByJob[title]['Billing Rate USD Monthly'] = brVal;
      reportByJob[title]['Estimated Annual Revenue USD'] = brVal * 12;

      if (sal.max > 0) {
        const salUSD = sal.max / 60.0;
        reportByJob[title]['Estimated Salary Max USD'] = Math.round(salUSD);
        const profit = brVal - salUSD;
        reportByJob[title]['Estimated Monthly Gross Profit USD'] = Math.round(profit);
        reportByJob[title]['Gross Margin %'] = brVal > 0 ? (profit / brVal) : 0;
      }
    }
  }

  // Data Quality check
  let dqNotes = [];
  if (!client) dqNotes.push('Missing Client');
  if (!salaryStr) dqNotes.push('Missing Salary');
  reportByJob[title]['Data Quality Notes'] = dqNotes.length > 0 ? dqNotes.join(', ') : 'OK';
}

// 2. Add Application-based counts
for (const app of applications) {
  const title = getJobTitleFromApplication(app);
  if (!title) continue;

  if (!reportByJob[title]) {
    reportByJob[title] = emptyRow(title);
  }

  // Total candidates count uses No_of_Candidates_Associated from JobOpenings, so we don't increment here.

  // Weekly activity: application touched/updated this week
  if (isWithinRange(app.Updated_On) || isWithinRange(app.Last_Activity_Time)) {
    reportByJob[title]['Candidates Worked This Week']++;
  }

  // Weekly booking invite activity
  if (isWithinRange(app.Booking_Link_Sent_Date)) {
    reportByJob[title]['Candidates Invited to Book']++;
  }
}

// 3. Add Interview-based counts
for (const interview of interviews) {
  const title = getJobTitleFromInterview(interview);
  if (!title) continue;

  if (!reportByJob[title]) {
    reportByJob[title] = emptyRow(title);
  }

  if (!isWithinRange(interview.Start_DateTime)) continue;

  const status = String(interview.Interview_Status || '').trim().toLowerCase();

  // Candidates booked this week
  reportByJob[title]['Candidates Booked']++;

  // Candidates interviewed this week
  const interviewedStatuses = ['shortlist', 'wait-list', 'move to next round', 'completed', 'no show'];
  if (interviewedStatuses.includes(status)) {
    reportByJob[title]['Candidates Interviewed']++;
  }
}

// 4. Sort and output rows
const rows = Object.values(reportByJob)
  .filter(row => row['Job Title'])
  .sort((a, b) => a['Job Title'].localeCompare(b['Job Title']));

return rows.map(row => ({ json: row }));

const rows = $input.all().map(item => item.json);

return [
  {
    json: {
      report_period: rows[0]?.['Report Period'] || '',
      generated_at: new Date().toISOString(),
      rows
    }
  }
];

const rows = $('Build Weekly Job Report Rows').all().map(item => item.json);
const range = $('Set Report Date Range').first().json;

const totalJobs = rows.length;
const activeJobs = rows.filter(r => r['Job Opening Status'] === 'In-progress').length;
const candidatesWorked = rows.reduce((sum, r) => sum + (r['Candidates Worked This Week'] || 0), 0);
const candidatesBooked = rows.reduce((sum, r) => sum + (r['Candidates Booked'] || 0), 0);
const candidatesInterviewed = rows.reduce((sum, r) => sum + (r['Candidates Interviewed'] || 0), 0);

const message = `📊 **Weekly Recruitment Report Summary**
🗓️ **Period:** ${range.report_label}

💼 **Job Openings:**
• Total Positions: **${totalJobs}**
• Active (In-progress): **${activeJobs}**

👥 **Weekly Activity:**
• Candidates Worked: **${candidatesWorked}**
• Candidates Booked: **${candidatesBooked}**
• Candidates Interviewed: **${candidatesInterviewed}**

📎 *The full Excel report is attached below.*`;

return [{ json: { message } }];
